import { Checkbox, LabelWrapper } from "@workspace/ui";
import { useFieldContext } from "../form-context";
import { DescriptionErrorWrapper } from "../lib/description-error-wrapper";

type CheckboxFieldProps = {
  label?: string;
  checkboxLabel?: string;
  required?: boolean;
};

export const CheckboxField = ({
  label,
  checkboxLabel,
  required,
  ...checkboxProps
}: CheckboxFieldProps) => {
  const field = useFieldContext<boolean | "indeterminate">();

  return (
    <LabelWrapper id={field.name} label={label} required={required}>
      <DescriptionErrorWrapper field={field}>
        <Checkbox
          checked={field.state.value}
          id={field.name}
          onBlur={field.handleBlur}
          onCheckedChange={(checked) => {
            field.handleChange(Boolean(checked));
          }}
          required={required}
          {...checkboxProps}
        >
          {checkboxLabel}
        </Checkbox>
      </DescriptionErrorWrapper>
    </LabelWrapper>
  );
};

