import { CheckboxWithLabel, LabelWrapper } from "@workspace/ui";
import { useFieldContext } from "../form-context";
import { DescriptionErrorWrapper } from "../lib/description-error-wrapper";

type CheckboxGroupFieldProps = {
  label?: string;
  items: {
    label: string;
    value: string;
  }[];
  required?: boolean;
  checkboxClassName?: string;
};

export const CheckboxGroupField = ({
  items,
  label,
  required,
  checkboxClassName,
}: CheckboxGroupFieldProps) => {
  const field = useFieldContext<string[]>();

  const handleCheckboxChange = (value: string, checked: boolean) => {
    if (checked) {
      field.handleChange([...(field.state.value ?? []), value]);
    } else {
      field.handleChange((field.state.value ?? []).filter((v) => v !== value));
    }
  };

  return (
    <LabelWrapper id={field.name} label={label} required={required}>
      <DescriptionErrorWrapper field={field}>
        {items.map((item) => {
          return (
            <CheckboxWithLabel
              checked={field.state.value?.includes(item.value) ?? false}
              className={checkboxClassName}
              id={`${field.name}-${item.value}`}
              key={`${item.value}-${item.label}-${item.label}`}
              labelClassName="capitalize"
              onCheckedChange={(checked) =>
                handleCheckboxChange(item.value, Boolean(checked))
              }
              value={item.value}
            >
              {item.label}
            </CheckboxWithLabel>
          );
        })}
      </DescriptionErrorWrapper>
    </LabelWrapper>
  );
};

